// Donnees de test
const body = $input.first().json.body || $input.first().json;
const clientName = body.clientName || 'TestClient';
const automationName = body.automationName || 'Workflow de test';
const folderId = body.folderId || null;

// Construire le workflow a creer
const workflow = {
  name: `[${clientName}] ${automationName}`,
  nodes: [
    {
      parameters: {
        rule: {
          interval: [{ field: 'hours', hoursInterval: 24 }]
        }
      },
      id: 'schedule-node',
      name: 'Declencheur quotidien',
      type: 'n8n-nodes-base.scheduleTrigger',
      typeVersion: 1.2,
      position: [250, 300]
    },
    {
      parameters: {
        jsCode: `// Workflow automatique pour ${clientName}\n// Cree automatiquement par TalosPrimes\nconst now = new Date().toISOString();\nreturn [{ json: { message: 'Bienvenue ${clientName}!', timestamp: now, status: 'ok' } }];`
      },
      id: 'code-node',
      name: 'Message bienvenue',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [470, 300]
    }
  ],
  connections: {
    'Declencheur quotidien': {
      main: [
        [{ node: 'Message bienvenue', type: 'main', index: 0 }]
      ]
    }
  },
  settings: { executionOrder: 'v1' }
};

return [{ json: { clientName, folderId, workflow } }];

const response = $input.first().json;
const workflowId = response.id || null;
const workflowName = response.name || null;
const folderId = $('02. Preparer').first().json.folderId;
const clientName = $('02. Preparer').first().json.clientName;

// Si on a un folderId, on peut deplacer
const canMove = !!(folderId && workflowId);

return [{ json: { workflowId, workflowName, folderId, clientName, canMove } }];

const data = $('04. Verifier resultat').first().json;
let movedToFolder = false;

try {
  const moveResult = $('06. Deplacer dans dossier').first();
  movedToFolder = moveResult && !moveResult.json?.message?.includes('error');
} catch {
  // pas de deplacement
}

return [{ json: {
  success: !!data.workflowId,
  workflowId: data.workflowId,
  workflowName: data.workflowName,
  clientName: data.clientName,
  movedToFolder,
  message: data.workflowId
    ? `Workflow "${data.workflowName}" cree${movedToFolder ? ' et deplace dans le dossier' : ''}`
    : 'Erreur: workflow non cree'
} }];
